--
-- Name: check_permission(integer, character varying, character varying); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.check_permission(p_user_id integer, p_resource character varying, p_action character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $_$
DECLARE
  user_role_v audit.user_role;
  has_permission BOOLEAN := FALSE;
BEGIN
  -- User-in rolunu tap
  SELECT role INTO user_role_v FROM audit.users WHERE id = p_user_id AND is_active;
  IF user_role_v IS NULL THEN RETURN FALSE; END IF;
  
  -- H√ľquq c…ôdv…ôlind…ôn yoxla
  EXECUTE format('SELECT can_%I FROM audit.permissions WHERE role = $1 AND resource = $2', p_action)
    INTO has_permission
    USING user_role_v, p_resource;
  
  RETURN COALESCE(has_permission, FALSE);
END;
$_$;


--
-- Name: log_login(character varying, character varying, inet, text, character varying, character varying); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.log_login(p_username character varying, p_status character varying, p_ip inet DEFAULT NULL::inet, p_user_agent text DEFAULT NULL::text, p_tailscale character varying DEFAULT NULL::character varying, p_failure_reason character varying DEFAULT NULL::character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
  u_id INT;
  log_id BIGINT;
BEGIN
  SELECT id INTO u_id FROM audit.users WHERE username = p_username;
  
    user_id, username, status, failure_reason,
    ip_address, user_agent, tailscale_name
  ) VALUES (
    u_id, p_username, p_status, p_failure_reason,
    p_ip, p_user_agent, p_tailscale
  ) RETURNING id INTO log_id;
  
  -- Uńüurlu login-d…ô user-in last_login-nu yenil…ô
  IF p_status = 'success' AND u_id IS NOT NULL THEN
    UPDATE audit.users 
      SET last_login = NOW(), last_ip = p_ip, failed_attempts = 0
      WHERE id = u_id;
  END IF;
  
  -- Uńüursuz c…ôhd ‚ÄĒ failed_attempts artńĪr
  IF p_status = 'failed' AND u_id IS NOT NULL THEN
    UPDATE audit.users 
      SET failed_attempts = failed_attempts + 1,
          locked_until = CASE WHEN failed_attempts + 1 >= 5 
                              THEN NOW() + INTERVAL '15 minutes' 
                              ELSE locked_until END
      WHERE id = u_id;
  END IF;
  
  RETURN log_id;
END;
$$;


