CREATE FUNCTION audit.log_query(p_user_id integer, p_action audit.action_type, p_resource character varying, p_query_text text DEFAULT NULL::text, p_ip inet DEFAULT NULL::inet, p_source character varying DEFAULT 'dashboard'::character varying, p_duration_ms integer DEFAULT NULL::integer, p_status character varying DEFAULT 'success'::character varying) RETURNS bigint
    LANGUAGE plpgsql
