    p_ip, p_source, p_duration_ms, p_status
  ) RETURNING id INTO log_id;
  
  RETURN log_id;
END;
$$;


--
-- Name: verify_password(character varying, character varying); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.verify_password(p_username character varying, p_password character varying) RETURNS TABLE(user_id integer, username character varying, full_name character varying, role audit.user_role, is_valid boolean, must_change_pwd boolean, locked boolean, error_msg text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  u RECORD;
BEGIN
  SELECT id, u2.username, u2.full_name, u2.role, u2.password_hash, 
         u2.is_active, u2.must_change_pwd, u2.locked_until, u2.failed_attempts
  INTO u
  FROM audit.users u2
  WHERE u2.username = p_username;
  
  -- ńįstifad…ô√ßi yoxdur
  IF NOT FOUND THEN
    RETURN QUERY SELECT NULL::INT, p_username, NULL::VARCHAR, NULL::audit.user_role,
                        FALSE, FALSE, FALSE, 'ńįstifad…ô√ßi tapńĪlmadńĪ'::TEXT;
    RETURN;
  END IF;
  
  -- Lock yoxla
  IF u.locked_until IS NOT NULL AND u.locked_until > NOW() THEN
    RETURN QUERY SELECT u.id, u.username, u.full_name, u.role,
                        FALSE, u.must_change_pwd, TRUE,
                        'Hesab bloklanńĪb. ' || EXTRACT(EPOCH FROM (u.locked_until - NOW()))/60 || ' d…ôqiq…ô sonra c…ôhd edin.';
    RETURN;
  END IF;
  
  -- Deaktiv
  IF NOT u.is_active THEN
    RETURN QUERY SELECT u.id, u.username, u.full_name, u.role,
                        FALSE, FALSE, FALSE, 'Hesab deaktivdir'::TEXT;
    RETURN;
  END IF;
  
  -- Password yoxla (crypt il…ô)
  IF u.password_hash = crypt(p_password, u.password_hash) THEN
    RETURN QUERY SELECT u.id, u.username, u.full_name, u.role,
                        TRUE, u.must_change_pwd, FALSE, NULL::TEXT;
  ELSE
    RETURN QUERY SELECT u.id, u.username, u.full_name, u.role,
                        FALSE, FALSE, FALSE, 'YanlńĪŇü parol'::TEXT;
  END IF;
END;
$$;


