CREATE FUNCTION construction.add_attachment(p_type character varying, p_parent_table character varying, p_parent_id integer, p_filename character varying, p_stored_name character varying, p_file_path character varying, p_file_size bigint, p_mime_type character varying, p_uploaded_by integer, p_source character varying DEFAULT 'mobile'::character varying, p_ip inet DEFAULT NULL::inet, p_title character varying DEFAULT NULL::character varying, p_description text DEFAULT NULL::text, p_gps_lat numeric DEFAULT NULL::numeric, p_gps_lng numeric DEFAULT NULL::numeric) RETURNS integer
    LANGUAGE plpgsql
    AS $_$
DECLARE
  new_id INT;
  user_role VARCHAR;
BEGIN
  -- User-in rolunu al
  SELECT role::TEXT INTO user_role FROM audit.users WHERE id = p_uploaded_by;
  
    attachment_type, parent_table, parent_id,
    filename, stored_name, file_path, file_size, mime_type,
    file_extension, uploaded_by, uploader_role, source, ip_address,
    title, description, gps_lat, gps_lng
  ) VALUES (
    p_type::construction.attachment_type, p_parent_table, p_parent_id,
    p_filename, p_stored_name, p_file_path, p_file_size, p_mime_type,
    LOWER(SUBSTRING(p_filename FROM '\.[^.]+$')),
    p_uploaded_by, user_role, p_source, p_ip,
    p_title, p_description, p_gps_lat, p_gps_lng
  ) RETURNING id INTO new_id;
  
  RETURN new_id;
END;
$_$;


--
-- Name: get_attachments(character varying, integer); Type: FUNCTION; Schema: construction; Owner: -
--

CREATE FUNCTION construction.get_attachments(p_parent_table character varying, p_parent_id integer) RETURNS TABLE(id integer, attachment_type construction.attachment_type, filename character varying, file_path character varying, file_size bigint, mime_type character varying, uploaded_by integer, uploader_name character varying, created_at timestamp without time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT a.id, a.attachment_type, a.filename, a.file_path, 
         a.file_size, a.mime_type, a.uploaded_by, u.full_name, a.created_at
  FROM construction.attachments a
  LEFT JOIN audit.users u ON a.uploaded_by = u.id
  WHERE a.parent_table = p_parent_table 
    AND a.parent_id = p_parent_id
    AND a.is_deleted = FALSE
  ORDER BY a.created_at DESC;
END;
$$;


