--
-- Name: v_active_users; Type: VIEW; Schema: audit; Owner: -
--

CREATE VIEW audit.v_active_users AS
 SELECT id,
    username,
    full_name,
    role,
    region_id,
    is_active,
    created_at,
    last_login,
        CASE
            WHEN (last_login > (now() - '24:00:00'::interval)) THEN 'Aktiv'::text
            WHEN (last_login > (now() - '7 days'::interval)) THEN 'YaxńĪn'::text
            ELSE 'Passiv'::text
        END AS status
   FROM audit.users
  WHERE (is_active = true);


--
-- Name: v_ip_stats; Type: VIEW; Schema: audit; Owner: -
--

CREATE VIEW audit.v_ip_stats AS
 SELECT (ip_address)::text AS ip,
    count(*) AS total_requests,
    count(DISTINCT username) AS unique_users,
    count(*) FILTER (WHERE ((status)::text = 'failed'::text)) AS failed_count,
    max(created_at) AS last_seen
   FROM audit.query_log
  WHERE (ip_address IS NOT NULL)
  GROUP BY ip_address
  ORDER BY (count(*)) DESC;


--
-- Name: v_recent_activity; Type: VIEW; Schema: audit; Owner: -
--

CREATE VIEW audit.v_recent_activity AS
 SELECT id,
    user_id,
    username,
    user_role,
    action,
    resource,
    source,
    status,
    created_at
   FROM audit.query_log ql
  WHERE (created_at > (now() - '24:00:00'::interval))
  ORDER BY created_at DESC;


--
-- Name: v_top_users; Type: VIEW; Schema: audit; Owner: -
--

CREATE VIEW audit.v_top_users AS
 SELECT username,
    user_role AS role,
    count(*) AS total_queries,
    count(DISTINCT date(created_at)) AS active_days,
    max(created_at) AS last_query
   FROM audit.query_log
  WHERE (created_at > (now() - '30 days'::interval))
  GROUP BY username, user_role
  ORDER BY (count(*)) DESC;


--
-- Name: v_user_stats; Type: VIEW; Schema: audit; Owner: -
--

CREATE VIEW audit.v_user_stats AS
 SELECT role,
    count(DISTINCT id) AS total_users,
    count(DISTINCT id) FILTER (WHERE is_active) AS active_users,
    count(DISTINCT id) FILTER (WHERE (last_login > (now() - '24:00:00'::interval))) AS active_24h
   FROM audit.users u
  GROUP BY role;


