--
-- Name: v_attachment_stats; Type: VIEW; Schema: construction; Owner: -
--

CREATE VIEW construction.v_attachment_stats AS
 SELECT count(*) AS total_files,
    count(*) FILTER (WHERE ((mime_type)::text ~~ 'image/%'::text)) AS total_images,
    count(*) FILTER (WHERE ((mime_type)::text = 'application/pdf'::text)) AS total_pdfs,
    count(*) FILTER (WHERE ((created_at)::date = CURRENT_DATE)) AS today_files,
    count(*) FILTER (WHERE ((source)::text = 'mobile'::text)) AS mobile_files,
    count(*) FILTER (WHERE ((source)::text = 'dashboard'::text)) AS dashboard_files,
    round((sum(file_size) / 1048576.0), 2) AS total_mb,
    count(DISTINCT uploaded_by) AS unique_uploaders,
    count(DISTINCT (((parent_table)::text || ':'::text) || parent_id)) AS attached_to_objects
   FROM construction.attachments
  WHERE (is_deleted = false);


