CREATE TABLE geo.regions (
    id integer NOT NULL,
    code character varying(10) NOT NULL,
    name_az character varying(100) NOT NULL,
    type_id integer NOT NULL,
    population integer,
    area_km2 numeric(10,2),
    center_lat numeric(9,6),
    center_lng numeric(9,6),
    is_active boolean DEFAULT true,
    school_count integer DEFAULT 0,
    created_at timestamp without time zone DEFAULT now(),
    CONSTRAINT regions_center_lat_check CHECK (((center_lat >= 38.0) AND (center_lat <= 42.0))),
    CONSTRAINT regions_center_lng_check CHECK (((center_lng >= 44.0) AND (center_lng <= 51.0))),
    CONSTRAINT regions_population_check CHECK ((population > 0))
);


--
-- Name: v_attachments_full; Type: VIEW; Schema: construction; Owner: -
--

CREATE VIEW construction.v_attachments_full AS
 SELECT a.id,
    a.attachment_type,
    a.parent_table,
    a.parent_id,
    a.filename,
    a.stored_name,
    a.file_path,
    a.file_size,
    round(((a.file_size)::numeric / 1024.0), 1) AS size_kb,
    a.mime_type,
    a.title,
    a.description,
    a.gps_lat,
    a.gps_lng,
    u.username AS uploader_username,
    u.full_name AS uploader_name,
    a.uploader_role,
    a.source,
    r.name_az AS region_name,
    a.thumbnail_path,
        CASE
            WHEN ((a.mime_type)::text ~~ 'image/%'::text) THEN 'image'::text
            WHEN ((a.mime_type)::text = 'application/pdf'::text) THEN 'pdf'::text
            ELSE 'other'::text
        END AS file_category,
        CASE
            WHEN (a.attachment_type = ANY (ARRAY['photo'::construction.attachment_type, 'inspection_photo'::construction.attachment_type, 'complaint_photo'::construction.attachment_type, 'progress_photo'::construction.attachment_type])) THEN 'ūüďł'::text
            WHEN (a.attachment_type = 'invoice'::construction.attachment_type) THEN 'ūüßĺ'::text
            WHEN (a.attachment_type = 'contract'::construction.attachment_type) THEN 'ūüďč'::text
            WHEN (a.attachment_type = 'receipt'::construction.attachment_type) THEN 'ūüßĺ'::text
            WHEN (a.attachment_type = 'blueprint'::construction.attachment_type) THEN 'ūüďź'::text
            WHEN (a.attachment_type = 'scan'::construction.attachment_type) THEN 'ūüďĄ'::text
            ELSE 'ūüďé'::text
        END AS icon,
    a.created_at
   FROM ((construction.attachments a
     LEFT JOIN audit.users u ON ((a.uploaded_by = u.id)))
     LEFT JOIN geo.regions r ON ((u.region_id = r.id)))
  WHERE (a.is_deleted = false);


