--
-- Name: v_budget_tracking; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_budget_tracking AS
 SELECT b.fiscal_year,
    COALESCE(r.name_az, '√úmumi'::character varying) AS region,
    b.category,
    b.source,
    b.allocated_amount,
    b.spent_amount,
    round((b.allocated_amount - b.spent_amount), 2) AS remaining,
        CASE
            WHEN (b.allocated_amount > (0)::numeric) THEN round(((100.0 * b.spent_amount) / b.allocated_amount), 1)
            ELSE (0)::numeric
        END AS execution_pct,
        CASE
            WHEN (b.allocated_amount = (0)::numeric) THEN 'BoŇü'::text
            WHEN ((b.spent_amount / b.allocated_amount) < 0.25) THEN 'AŇüańüńĪ icra'::text
            WHEN ((b.spent_amount / b.allocated_amount) < 0.75) THEN 'Orta icra'::text
            WHEN ((b.spent_amount / b.allocated_amount) < 0.95) THEN 'YaxŇüńĪ icra'::text
            ELSE 'Tam icra'::text
        END AS execution_level
   FROM (finance.budgets b
     LEFT JOIN geo.regions r ON ((b.region_id = r.id)));


--
-- Name: mv_budget_tracking; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_budget_tracking AS
 SELECT fiscal_year,
    region,
    category,
    source,
    allocated_amount,
    spent_amount,
    remaining,
    execution_pct,
    execution_level
   FROM reporting.v_budget_tracking
  WITH NO DATA;


--
-- Name: v_complaint_analysis; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_complaint_analysis AS
 SELECT cc.id AS complaint_id,
    cc.complaint_date,
    cc.channel,
    cc.category,
    cc.urgency,
    cc.status,
    cc.resolution_days,
    r.name_az AS region,
    s.name AS school_name,
    p.project_code,
    "left"(cc.text, 80) AS complaint_preview,
        CASE
            WHEN (((cc.status)::text = 'resolved'::text) AND (cc.resolution_days <= 7)) THEN '‚≠ź S√ľr…ôtli'::text
            WHEN (((cc.status)::text = 'resolved'::text) AND (cc.resolution_days <= 30)) THEN '‚úÖ Normal'::text
            WHEN ((cc.status)::text = 'resolved'::text) THEN 'ūüü° YavaŇü'::text
            WHEN ((cc.status)::text = 'investigating'::text) THEN 'ūüĒć ńįnceleme'::text
            WHEN ((cc.status)::text = 'new'::text) THEN 'ūüÜē Yeni'::text
            ELSE 'ūüďĀ BańülńĪ'::text
        END AS resolution_label
   FROM (((construction.citizen_complaints cc
     LEFT JOIN infra.schools s ON ((cc.school_id = s.id)))
     LEFT JOIN geo.regions r ON ((s.region_id = r.id)))
     LEFT JOIN construction.projects p ON ((cc.project_id = p.id)));


--
-- Name: mv_complaint_analysis; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_complaint_analysis AS
 SELECT complaint_id,
    complaint_date,
    channel,
    category,
    urgency,
    status,
    resolution_days,
    region,
    school_name,
    project_code,
    complaint_preview,
    resolution_label
   FROM reporting.v_complaint_analysis
  WITH NO DATA;


--
-- Name: v_contractor_performance; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_contractor_performance AS
 SELECT c.id AS contractor_id,
    c.name AS contractor_name,
    c.tin,
    c.category,
    c.rating,
    c.is_blacklisted,
    count(DISTINCT p.id) AS total_projects,
    count(DISTINCT p.id) FILTER (WHERE ((p.status)::text = 'completed'::text)) AS completed,
    count(DISTINCT p.id) FILTER (WHERE ((p.status)::text = 'in_progress'::text)) AS active,
    COALESCE(round((sum(p.actual_cost) / (1000)::numeric), 0), (0)::numeric) AS total_revenue_k,
    COALESCE(round(avg(ins.quality_score), 1), (0)::numeric) AS avg_quality,
    count(DISTINCT ins.id) AS inspection_count,
    count(DISTINCT comp.id) AS complaint_count
   FROM (((hr.contractors c
     LEFT JOIN construction.projects p ON ((p.contractor_id = c.id)))
     LEFT JOIN construction.inspections ins ON ((ins.project_id = p.id)))
     LEFT JOIN construction.citizen_complaints comp ON ((comp.project_id = p.id)))
  GROUP BY c.id, c.name, c.tin, c.category, c.rating, c.is_blacklisted;


--
-- Name: mv_contractor_performance; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_contractor_performance AS
 SELECT contractor_id,
    contractor_name,
    tin,
    category,
    rating,
    is_blacklisted,
    total_projects,
    completed,
    active,
    total_revenue_k,
    avg_quality,
    inspection_count,
    complaint_count
   FROM reporting.v_contractor_performance
  WITH NO DATA;


--
-- Name: v_deadline_monitoring; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_deadline_monitoring AS
 SELECT p.id AS project_id,
    p.project_code,
    p.name AS project_name,
    r.name_az AS region,
    p.status,
    p.progress_percent,
    p.end_date AS planned_end,
    p.actual_end,
    (CURRENT_DATE - p.end_date) AS days_overdue,
    (p.end_date - CURRENT_DATE) AS days_remaining,
        CASE
            WHEN (((p.status)::text = 'completed'::text) AND (p.actual_end > p.end_date)) THEN 'GecikmiŇüdi'::text
            WHEN ((p.status)::text = 'completed'::text) THEN 'VaxtńĪnda'::text
            WHEN ((p.status)::text = ANY ((ARRAY['planned'::character varying, 'approved'::character varying])::text[])) THEN 'BaŇülamayńĪb'::text
            WHEN (CURRENT_DATE > p.end_date) THEN 'GECńįKńįR!'::text
            WHEN ((p.end_date - CURRENT_DATE) <= 30) THEN 'Deadline yaxńĪn'::text
            ELSE 'Normal'::text
        END AS deadline_status,
    p.planned_budget,
    p.actual_cost
   FROM (construction.projects p
     LEFT JOIN geo.regions r ON ((p.region_id = r.id)));


--
-- Name: mv_deadline_monitoring; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_deadline_monitoring AS
 SELECT project_id,
    project_code,
    project_name,
    region,
    status,
    progress_percent,
    planned_end,
    actual_end,
    days_overdue,
    days_remaining,
    deadline_status,
    planned_budget,
    actual_cost
   FROM reporting.v_deadline_monitoring
  WITH NO DATA;


--
-- Name: v_inspection_summary; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_inspection_summary AS
 SELECT ins.id AS inspection_id,
    ins.inspection_date,
    ins.inspection_type,
    p.project_code,
    p.name AS project_name,
    r.name_az AS region,
    e.full_name AS inspector_name,
    ins.quality_score,
    ins.issues_found,
    ins.issues_resolved,
    (ins.issues_found - ins.issues_resolved) AS unresolved,
    ins.requires_followup,
        CASE
            WHEN (ins.quality_score >= (9)::numeric) THEN '‚≠ź ∆Źla'::text
            WHEN (ins.quality_score >= (7)::numeric) THEN '‚úÖ YaxŇüńĪ'::text
            WHEN (ins.quality_score >= (5)::numeric) THEN 'ūüü° Orta'::text
            ELSE '‚ĚĆ Pis'::text
        END AS quality_label
   FROM (((construction.inspections ins
     LEFT JOIN construction.projects p ON ((ins.project_id = p.id)))
     LEFT JOIN geo.regions r ON ((p.region_id = r.id)))
     LEFT JOIN hr.employees e ON ((ins.inspector_id = e.id)));


