    unresolved,
    requires_followup,
    quality_label
   FROM reporting.v_inspection_summary
  WITH NO DATA;


--
-- Name: v_kpi_dashboard; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_kpi_dashboard AS
 SELECT ( SELECT count(*) AS count
           FROM geo.regions
          WHERE regions.is_active) AS total_regions,
    ( SELECT count(*) AS count
           FROM infra.schools
          WHERE schools.is_active) AS total_schools,
    ( SELECT count(*) AS count
           FROM construction.projects) AS total_projects,
    ( SELECT count(*) AS count
           FROM construction.projects
          WHERE ((projects.status)::text = 'in_progress'::text)) AS active_projects,
    ( SELECT count(*) AS count
           FROM construction.projects
          WHERE ((projects.status)::text = 'completed'::text)) AS completed_projects,
    ( SELECT round((sum(projects.planned_budget) / (1000000)::numeric), 1) AS round
           FROM construction.projects) AS total_planned_mln,
    ( SELECT round((sum(projects.actual_cost) / (1000000)::numeric), 1) AS round
           FROM construction.projects) AS total_spent_mln,
    ( SELECT round(avg(projects.progress_percent), 1) AS round
           FROM construction.projects
          WHERE ((projects.status)::text = 'in_progress'::text)) AS avg_progress,
    ( SELECT count(*) AS count
           FROM hr.employees
          WHERE employees.is_active) AS total_employees,
    ( SELECT count(*) AS count
           FROM hr.contractors
          WHERE (NOT contractors.is_blacklisted)) AS total_contractors,
    ( SELECT count(*) AS count
           FROM construction.citizen_complaints
          WHERE ((citizen_complaints.status)::text = ANY ((ARRAY['new'::character varying, 'investigating'::character varying])::text[]))) AS pending_complaints,
    ( SELECT round(avg(inspections.quality_score), 1) AS round
           FROM construction.inspections) AS avg_quality;


--
-- Name: mv_kpi; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_kpi AS
 SELECT total_regions,
    total_schools,
    total_projects,
    active_projects,
    completed_projects,
    total_planned_mln,
    total_spent_mln,
    avg_progress,
    total_employees,
    total_contractors,
    pending_complaints,
    avg_quality
   FROM reporting.v_kpi_dashboard
  WITH NO DATA;


--
-- Name: v_material_flow; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_material_flow AS
 SELECT m.id AS material_id,
    m.code,
    m.name_az AS material_name,
    mc.name_az AS category,
    mc.icon,
    m.unit,
    m.standard_price,
    COALESCE(sum(st.quantity), (0)::numeric) AS total_stock,
    count(DISTINCT st.warehouse_id) AS warehouses_with_stock,
    COALESCE(sum(mt.quantity) FILTER (WHERE ((mt.transaction_type)::text = 'in'::text)), (0)::numeric) AS total_in,
    COALESCE(sum(mt.quantity) FILTER (WHERE ((mt.transaction_type)::text = 'out'::text)), (0)::numeric) AS total_out,
    COALESCE(sum(mt.total_amount) FILTER (WHERE ((mt.transaction_type)::text = 'out'::text)), (0)::numeric) AS total_out_value,
    m.min_stock_level,
        CASE
            WHEN (COALESCE(sum(st.quantity), (0)::numeric) < m.min_stock_level) THEN '‚ö†ÔłŹ Az'::text
            WHEN (COALESCE(sum(st.quantity), (0)::numeric) < (m.min_stock_level * (2)::numeric)) THEN 'ūüü° Orta'::text
            ELSE '‚úÖ YaxŇüńĪ'::text
        END AS stock_status
   FROM (((inventory.materials m
     LEFT JOIN inventory.material_categories mc ON ((m.category_id = mc.id)))
     LEFT JOIN inventory.stock_levels st ON ((st.material_id = m.id)))
     LEFT JOIN inventory.material_transactions mt ON ((mt.material_id = m.id)))
  GROUP BY m.id, m.code, m.name_az, mc.name_az, mc.icon, m.unit, m.standard_price, m.min_stock_level;


--
-- Name: mv_material_flow; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_material_flow AS
 SELECT material_id,
    code,
    material_name,
    category,
    icon,
    unit,
    standard_price,
    total_stock,
    warehouses_with_stock,
    total_in,
    total_out,
    total_out_value,
    min_stock_level,
    stock_status
   FROM reporting.v_material_flow
  WITH NO DATA;


--
-- Name: v_monthly_spending; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_monthly_spending AS
 SELECT (EXTRACT(year FROM expense_date))::integer AS year,
    (EXTRACT(month FROM expense_date))::integer AS month,
    to_char((expense_date)::timestamp with time zone, 'YYYY-MM'::text) AS year_month,
    category,
    count(*) AS transaction_count,
    round(sum(amount), 2) AS total_amount,
    round(avg(amount), 2) AS avg_amount
   FROM finance.expenses
  GROUP BY (EXTRACT(year FROM expense_date)), (EXTRACT(month FROM expense_date)), (to_char((expense_date)::timestamp with time zone, 'YYYY-MM'::text)), category
  ORDER BY ((EXTRACT(year FROM expense_date))::integer), ((EXTRACT(month FROM expense_date))::integer), category;


--
-- Name: mv_monthly_spending; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_monthly_spending AS
 SELECT year,
    month,
    year_month,
    category,
    transaction_count,
    total_amount,
    avg_amount
   FROM reporting.v_monthly_spending
  WITH NO DATA;


--
-- Name: v_project_status; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_project_status AS
 SELECT p.id AS project_id,
    p.project_code,
    p.name AS project_name,
    pt.name_az AS project_type,
    pt.icon,
    r.name_az AS region_name,
    s.name AS school_name,
    c.name AS contractor_name,
    e.full_name AS manager_name,
    p.status,
    p.priority,
    p.progress_percent,
    p.start_date,
    p.end_date,
    p.actual_start,
    p.actual_end,
    p.planned_budget,
    p.actual_cost,
    round((p.actual_cost - p.planned_budget), 2) AS cost_variance,
        CASE
            WHEN (p.planned_budget > (0)::numeric) THEN round(((100.0 * (p.actual_cost - p.planned_budget)) / p.planned_budget), 1)
            ELSE (0)::numeric
        END AS cost_variance_pct,
        CASE
            WHEN (((p.status)::text = 'completed'::text) AND (p.actual_end > p.end_date)) THEN 'Gecikm…ô il…ô bitib'::text
            WHEN (((p.status)::text = 'completed'::text) AND (p.actual_end <= p.end_date)) THEN 'VaxtńĪnda bitib'::text
            WHEN (((p.status)::text = 'in_progress'::text) AND (CURRENT_DATE > p.end_date)) THEN 'Gecikir'::text
            WHEN ((p.status)::text = 'in_progress'::text) THEN 'Planda davam edir'::text
            WHEN ((p.status)::text = 'planned'::text) THEN 'PlanlaŇüdńĪrńĪlńĪb'::text
            WHEN ((p.status)::text = 'approved'::text) THEN 'T…ôsdiql…ônib'::text
            WHEN ((p.status)::text = 'on_hold'::text) THEN 'DayandńĪrńĪlńĪb'::text
            ELSE 'L…ôńüv edilib'::text
        END AS status_label
   FROM (((((construction.projects p
     LEFT JOIN construction.project_types pt ON ((p.type_id = pt.id)))
     LEFT JOIN geo.regions r ON ((p.region_id = r.id)))
     LEFT JOIN infra.schools s ON ((p.school_id = s.id)))
     LEFT JOIN hr.contractors c ON ((p.contractor_id = c.id)))
     LEFT JOIN hr.employees e ON ((p.manager_id = e.id)));


--
-- Name: mv_project_status; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_project_status AS
 SELECT project_id,
    project_code,
    project_name,
    project_type,
    icon,
    region_name,
    school_name,
    contractor_name,
    manager_name,
    status,
    priority,
    progress_percent,
    start_date,
    end_date,
    actual_start,
    actual_end,
    planned_budget,
    actual_cost,
    cost_variance,
    cost_variance_pct,
    status_label
   FROM reporting.v_project_status
  WITH NO DATA;


--
-- Name: v_regional_overview; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_regional_overview AS
 SELECT r.id AS region_id,
    r.code,
    r.name_az AS region_name,
    r.population,
    r.center_lat AS lat,
    r.center_lng AS lng,
    count(DISTINCT s.id) AS school_count,
    count(DISTINCT p.id) AS project_count,
    count(DISTINCT p.id) FILTER (WHERE ((p.status)::text = 'in_progress'::text)) AS active_projects,
    count(DISTINCT p.id) FILTER (WHERE ((p.status)::text = 'completed'::text)) AS completed_projects,
    COALESCE(round((sum(p.planned_budget) / (1000000)::numeric), 2), (0)::numeric) AS planned_mln,
    COALESCE(round((sum(p.actual_cost) / (1000000)::numeric), 2), (0)::numeric) AS spent_mln,
    COALESCE(round(avg(p.progress_percent)), (0)::numeric) AS avg_progress
   FROM ((geo.regions r
     LEFT JOIN infra.schools s ON ((s.region_id = r.id)))
     LEFT JOIN construction.projects p ON ((p.region_id = r.id)))
  GROUP BY r.id, r.code, r.name_az, r.population, r.center_lat, r.center_lng;


--
-- Name: mv_regional_overview; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_regional_overview AS
 SELECT region_id,
    code,
    region_name,
    population,
    lat,
    lng,
    school_count,
    project_count,
    active_projects,
    completed_projects,
    planned_mln,
    spent_mln,
    avg_progress
   FROM reporting.v_regional_overview
  WITH NO DATA;


--
-- Name: v_top_projects_by_budget; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_top_projects_by_budget AS
 SELECT p.id AS project_id,
    p.project_code,
    p.name,
    pt.name_az AS type_name,
    pt.icon,
    r.name_az AS region,
    s.name AS school_name,
    p.status,
    p.progress_percent,
    p.planned_budget,
    p.actual_cost,
    round((p.planned_budget / (1000)::numeric), 0) AS budget_k_azn,
    row_number() OVER (ORDER BY p.planned_budget DESC) AS rank
   FROM (((construction.projects p
     LEFT JOIN construction.project_types pt ON ((p.type_id = pt.id)))
     LEFT JOIN geo.regions r ON ((p.region_id = r.id)))
     LEFT JOIN infra.schools s ON ((p.school_id = s.id)))
  ORDER BY p.planned_budget DESC;


--
-- Name: mv_top_projects; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_top_projects AS
 SELECT project_id,
    project_code,
    name,
    type_name,
    icon,
    region,
    school_name,
    status,
    progress_percent,
    planned_budget,
    actual_cost,
    budget_k_azn,
    rank
   FROM reporting.v_top_projects_by_budget
  WITH NO DATA;


--
-- Name: v_yearly_summary; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_yearly_summary AS
 SELECT (EXTRACT(year FROM start_date))::integer AS year,
    count(*) AS projects_started,
    count(*) FILTER (WHERE ((status)::text = 'completed'::text)) AS projects_completed,
    round((sum(planned_budget) / (1000000)::numeric), 2) AS total_planned_mln,
    round((sum(actual_cost) / (1000000)::numeric), 2) AS total_spent_mln,
    round(avg(progress_percent)) AS avg_progress,
    count(DISTINCT region_id) AS regions_involved,
    count(DISTINCT contractor_id) AS contractors_involved
   FROM construction.projects p
  WHERE (start_date IS NOT NULL)
  GROUP BY (EXTRACT(year FROM start_date))
  ORDER BY ((EXTRACT(year FROM start_date))::integer);


--
-- Name: mv_yearly_summary; Type: MATERIALIZED VIEW; Schema: reporting; Owner: -
--

CREATE MATERIALIZED VIEW reporting.mv_yearly_summary AS
 SELECT year,
    projects_started,
    projects_completed,
    total_planned_mln,
    total_spent_mln,
    avg_progress,
    regions_involved,
    contractors_involved
   FROM reporting.v_yearly_summary
  WITH NO DATA;


--
-- Name: v_employee_workload; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_employee_workload AS
 SELECT e.id AS employee_id,
    e.full_name,
    pos.name_az AS position_name,
    d.name_az AS department_name,
    r.name_az AS region,
    e.monthly_salary,
    count(DISTINCT p.id) AS managed_projects,
    count(DISTINCT p.id) FILTER (WHERE ((p.status)::text = 'in_progress'::text)) AS active_projects,
    count(DISTINCT ins.id) AS inspections_done,
    count(DISTINCT exp.id) AS expenses_approved
   FROM ((((((hr.employees e
     LEFT JOIN hr.positions pos ON ((e.position_id = pos.id)))
     LEFT JOIN hr.departments d ON ((e.department_id = d.id)))
     LEFT JOIN geo.regions r ON ((e.region_id = r.id)))
     LEFT JOIN construction.projects p ON ((p.manager_id = e.id)))
     LEFT JOIN construction.inspections ins ON ((ins.inspector_id = e.id)))
     LEFT JOIN finance.expenses exp ON ((exp.approved_by = e.id)))
  WHERE (e.is_active = true)
  GROUP BY e.id, e.full_name, pos.name_az, d.name_az, r.name_az, e.monthly_salary;


--
-- Name: v_school_repair_history; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_school_repair_history AS
 SELECT s.id AS school_id,
    s.code,
    s.name AS school_name,
    r.name_az AS region,
    s.condition,
    s.built_year,
    s.student_count,
    s.last_major_repair,
    count(p.id) AS total_projects,
    count(p.id) FILTER (WHERE ((p.status)::text = 'completed'::text)) AS completed_projects,
    COALESCE(round((sum(p.planned_budget) / (1000)::numeric), 0), (0)::numeric) AS total_budget_k,
    COALESCE(round((sum(p.actual_cost) / (1000)::numeric), 0), (0)::numeric) AS total_spent_k,
    max(p.actual_end) AS last_project_end
   FROM ((infra.schools s
     LEFT JOIN geo.regions r ON ((s.region_id = r.id)))
     LEFT JOIN construction.projects p ON ((p.school_id = s.id)))
  GROUP BY s.id, s.code, s.name, r.name_az, s.condition, s.built_year, s.student_count, s.last_major_repair;


--
-- Name: v_warehouse_summary; Type: VIEW; Schema: reporting; Owner: -
--

CREATE VIEW reporting.v_warehouse_summary AS
 SELECT w.id AS warehouse_id,
    w.code,
    w.name AS warehouse_name,
    r.name_az AS region,
    w.area_m2,
    w.is_central,
    e.full_name AS manager_name,
    count(DISTINCT sl.material_id) AS materials_stocked,
    round(sum(sl.quantity), 2) AS total_quantity,
    round(sum((sl.quantity * m.standard_price)), 2) AS total_value
   FROM ((((inventory.warehouses w
     LEFT JOIN geo.regions r ON ((w.region_id = r.id)))
     LEFT JOIN hr.employees e ON ((w.manager_id = e.id)))
     LEFT JOIN inventory.stock_levels sl ON ((sl.warehouse_id = w.id)))
     LEFT JOIN inventory.materials m ON ((sl.material_id = m.id)))
  GROUP BY w.id, w.code, w.name, r.name_az, w.area_m2, w.is_central, e.full_name;


